sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {

    // 1. Declare an empty array called 'answer'
    var answer = [];

    // 2. Declare variables for each of the accepted names in the request body
    var make, model, vin, year, country, city;

    // 3. Declare a variable called requestBody with an initial value of the request.body object
    var requestBody = request.body;

    // 4. Declare a variable called requestString, converting request.body to string using dataString()
    var requestString = request.body.dataString;

    // 5. Declare a variable called result that converts requestString into an array
    var result = JSON.parse(requestString);
    try {

        // 6. For every vehicle in the array create a record in the x_snc_vehicle_ma_0_vehicle table
        for (var i = 0; i < result.vehicles.length; i++) {
            make = result.vehicles[i].make;
            model = result.vehicles[i].model;
            vin = result.vehicles[i].vin;
            year = result.vehicles[i].year;
            country = result.vehicles[i].country;
            city = result.vehicles[i].city;
            var vehicleGR = new GlideRecord('x_snc_vehicle_ma_0_vehicle');
            vehicleGR.initialize();
            vehicleGR.setValue('make', make);
            vehicleGR.setValue('model', model);
            vehicleGR.setValue('vin', vin);
            vehicleGR.setValue('year', year);
            vehicleGR.setValue('country', country);
            vehicleGR.setValue('city', city);
            vehicleGR.insert();

            // 7. For every vehicle create an object with vin and sys_id and push into answer
            var vehicleObj = {
                vin: vehicleGR.vin,
                sys_id: vehicleGR.sys_id
            };
            answer.push(vehicleObj);
        }
		response.setStatus(201);

        // 8. Generate a response body that contains the 'answer' variable
        response.setBody({
            answer: answer
        });
    } catch (ex) {

        // 9. If an error occurs, generate a 500 HTTP error with a generic message
        response.setStatus(500);
        response.setBody({
            error: {
                message: 'Internal Server Error',
                detail: 'An error occurred while processing the request'
            }
        });
    }
})(request, response);
